import { Component } from '@angular/core';

@Component({
  selector: 'app-counter',
  template: `
    <div>
      <h2>Count: {{ count }}</h2>
      <p>Step: {{ step }} | Min: {{ min }} | Max: {{ max }}</p>

      <button (click)="decrement()">-</button>
      <button (click)="increment()">+</button>
      <button (click)="reset()">Reset</button>
    </div>
  `
})
export class CounterComponent {
  count = 0;
  step = 1;
  min = 0;
  max = 10;

  increment() {
    const next = this.count + this.step;
    this.count = next <= this.max ? next : this.max;
  }

  decrement() {
    const next = this.count - this.step;
    this.count = next >= this.min ? next : this.min;
  }

  reset() {
    this.count = 0;
  }
}

